def is_kaggle() -> bool:
    return Path("/kaggle/working").exists()


def run(cmd: list[str], cwd: Path | None = None) -> None:
    print("$ " + " ".join(cmd), flush=True)
    subprocess.run(cmd, cwd=str(cwd) if cwd else None, check=True)


def find_payload() -> Path:
    candidates = [SCRIPT_PAYLOAD, DATASET_PAYLOAD, Path("scres_ia_payload.tar.gz")]
    if is_kaggle():
        candidates.extend(sorted(Path("/kaggle/input").glob("**/scres_ia_payload.tar.gz")))
    for candidate in candidates:
        if candidate.exists():
            print(f"[kernel] using payload {candidate}", flush=True)
            return candidate
    if EMBEDDED_PAYLOAD_B64.strip():
        target = Path("/kaggle/working/scres_ia_payload.tar.gz") if is_kaggle() else Path("scres_ia_payload.tar.gz")
        print(f"[kernel] writing embedded payload {target}", flush=True)
        target.write_bytes(base64.b64decode(EMBEDDED_PAYLOAD_B64))
        return target
    raise FileNotFoundError("Missing scres_ia_payload.tar.gz beside kernel or in Kaggle input.")


def extract_payload() -> Path:
    repo_dir = REPO_DIR if is_kaggle() else LOCAL_REPO_DIR.resolve()
    if repo_dir.exists():
        shutil.rmtree(repo_dir)
    repo_dir.mkdir(parents=True, exist_ok=True)
    try:
        payload = find_payload()
    except FileNotFoundError as exc:
        if not is_kaggle():
            raise
        print(f"[kernel] payload unavailable ({exc}); cloning {GIT_BRANCH}", flush=True)
        shutil.rmtree(repo_dir)
        run(["git", "clone", "--depth", "1", "--branch", GIT_BRANCH, GIT_REPO_URL, str(repo_dir)])
    else:
        print(f"[kernel] extracting {payload} -> {repo_dir}", flush=True)
        with tarfile.open(payload, "r:gz") as archive:
            archive.extractall(repo_dir)
    required = [
        repo_dir / "requirements.txt",
        repo_dir / "scripts" / "run_track_b_smoke.py",
        repo_dir / "supply_chain" / "supply_chain.py",
        repo_dir / "supply_chain" / "external_env_interface.py",
    ]
    missing = [str(path) for path in required if not path.exists()]
    if missing:
        raise FileNotFoundError(f"Payload preflight failed; missing: {missing}")
    smoke_src = (repo_dir / "scripts" / "run_track_b_smoke.py").read_text(encoding="utf-8")
    if '"sac"' not in smoke_src or '"td3"' not in smoke_src:
        raise RuntimeError(
            "Payload preflight failed: run_track_b_smoke.py is stale (missing sac/td3 --algo support)."
        )
    return repo_dir


def run_algo(repo_dir: Path, out_dir: Path, algo: str, profile: str) -> None:
    if profile == "smoke":
        seeds = ["1"]
        train_timesteps = "512"
        eval_episodes = "1"
        max_steps = "8"
    elif profile == "confirmatory":
        seeds = ["1", "2", "3", "4", "5"]
        train_timesteps = "60000"
        eval_episodes = "12"
        max_steps = "104"
    else:
        raise ValueError("profile must be smoke or confirmatory")

    cmd = [
        sys.executable,
        "scripts/run_track_b_smoke.py",
        "--algo", algo,
        "--output-dir", str(out_dir),
        "--seeds", *seeds,
        "--train-timesteps", train_timesteps,
        "--eval-episodes", eval_episodes,
        "--max-steps", max_steps,
        "--risk-level", "adaptive_benchmark_v2",
        "--reward-mode", "control_v1",
        "--observation-version", "v7",
        "--learning-rate", "0.0003",
        "--batch-size", "256",
        "--gamma", "0.99",
    ]
    run(cmd, cwd=repo_dir)


def main() -> int:
    import os

    profile = os.environ.get("SCRESIA_PROFILE", "confirmatory")
    repo_dir = extract_payload()
    if is_kaggle():
        run([sys.executable, "-m", "pip", "install", "-q", "-r", "requirements.txt"], cwd=repo_dir)
    out_dir = OUTPUT_DIR if is_kaggle() else LOCAL_OUTPUT_DIR.resolve()
    out_dir.mkdir(parents=True, exist_ok=True)

    run_algo(repo_dir, out_dir / "sac", "sac", profile)
    run_algo(repo_dir, out_dir / "td3", "td3", profile)

    manifest = {
        "generated_at_utc": datetime.now(timezone.utc).isoformat(),
        "profile": profile,
        "algorithms": ["sac", "td3"],
        "hyperparameters": {
            "reward_mode": "control_v1",
            "risk_level": "adaptive_benchmark_v2",
            "observation_version": "v7",
            "seeds": [1, 2, 3, 4, 5] if profile == "confirmatory" else [1],
            "train_timesteps": 60000 if profile == "confirmatory" else 512,
            "eval_episodes": 12 if profile == "confirmatory" else 1,
            "max_steps": 104 if profile == "confirmatory" else 8,
            "learning_rate": 0.0003,
            "batch_size": 256,
            "gamma": 0.99,
        },
        "output_dir": str(out_dir),
        "purpose": (
            "Off-policy algorithm-scope screen: does the Track B win survive under "
            "SAC/TD3 instead of PPO, at canonical protocol and confirmatory scale?"
        ),
    }
    (out_dir / "sac_td3_manifest.json").write_text(json.dumps(manifest, indent=2), encoding="utf-8")
    print(f"[kernel] done -> {out_dir}", flush=True)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
